/// Controls whether a [BTAccordion] allows one or multiple items open
/// simultaneously.
enum BTAccordionType {
  /// Only one item may be expanded at a time.
  single,

  /// Any number of items may be expanded simultaneously.
  multiple,
}

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/organisms/accordion/accordion.types.dart';
import 'package:flutter/material.dart';

// ── Group InheritedWidget ────────────────────────────────────────────────────

/// Internal scope injected by [BTAccordion] into the widget tree.
/// [BTAccordionItem] widgets look up this scope to participate in group
/// open/close logic.
class _BTAccordionScope extends InheritedWidget {
  const _BTAccordionScope({
    required this.isItemOpen,
    required this.onToggle,
    required super.child,
  });

  final bool Function(String value) isItemOpen;
  final void Function(String value) onToggle;

  static _BTAccordionScope? maybeOf(BuildContext context) =>
      context.dependOnInheritedWidgetOfExactType<_BTAccordionScope>();

  @override
  bool updateShouldNotify(_BTAccordionScope oldWidget) => true;
}

// ── BTAccordion ──────────────────────────────────────────────────────────────

/// BTAccordion — group wrapper for collapsible [BTAccordionItem] panels
/// (Figma 2473:2493).
///
/// Manages which items are open (single or multiple). Renders no visual chrome
/// of its own — place [BTAccordionItem] children inside.
///
/// For a card-style expandable panel with its own header, use [BTAccordionCard].
///
/// Example:
/// ```dart
/// // Uncontrolled single — default
/// BTAccordion(
///   children: [
///     BTAccordionItem(value: 'a', title: 'First', child: Text('Content A')),
///     BTAccordionItem(value: 'b', title: 'Second', child: Text('Content B')),
///   ],
/// )
///
/// // Multiple — any number open simultaneously
/// BTAccordion(
///   type: BTAccordionType.multiple,
///   children: [
///     BTAccordionItem(value: 'a', title: 'First', child: Text('Content A')),
///     BTAccordionItem(value: 'b', title: 'Second', child: Text('Content B')),
///   ],
/// )
///
/// // Controlled (single)
/// BTAccordion(
///   value: _openValue,
///   onValueChange: (v) => setState(() => _openValue = v),
///   children: [
///     BTAccordionItem(value: 'a', title: 'First', child: Text('Content A')),
///   ],
/// )
/// ```
class BTAccordion extends StatefulWidget {
  const BTAccordion({
    required this.children,
    this.type = BTAccordionType.single,
    this.value,
    this.onValueChange,
    super.key,
  });

  /// Controls whether one or many items can be open simultaneously.
  /// @default [BTAccordionType.single]
  final BTAccordionType type;

  /// Currently open item value (single mode) or list of open values (multiple
  /// mode). `null` / empty list means all collapsed. Omit for uncontrolled.
  final dynamic value;

  /// Called when the user expands/collapses an item.
  /// Receives `String?` in single mode, `List<String>` in multiple mode.
  final void Function(dynamic value)? onValueChange;

  /// [BTAccordionItem] children. Each must have a unique [BTAccordionItem.value].
  final List<Widget> children;

  @override
  State<BTAccordion> createState() => _BTAccordionState();
}

class _BTAccordionState extends State<BTAccordion> {
  String? _internalSingle;
  Set<String> _internalMultiple = {};

  bool _isItemOpen(String itemValue) {
    if (widget.type == BTAccordionType.multiple) {
      final controlled = widget.value;
      final set = controlled is List<String>
          ? controlled.toSet()
          : controlled is Set<String>
              ? controlled
              : _internalMultiple;
      return set.contains(itemValue);
    }
    final controlled = widget.value is String ? widget.value as String? : null;
    return (controlled ?? _internalSingle) == itemValue;
  }

  void _toggle(String itemValue) {
    if (widget.type == BTAccordionType.multiple) {
      final currentControlled = widget.value;
      final current = currentControlled is List<String>
          ? currentControlled.toSet()
          : currentControlled is Set<String>
              ? currentControlled
              : Set<String>.from(_internalMultiple);
      final next = current.contains(itemValue)
          ? (current..remove(itemValue))
          : (current..add(itemValue));
      if (widget.value == null) {
        setState(() => _internalMultiple = Set<String>.from(next));
      }
      widget.onValueChange?.call(next.toList());
    } else {
      final currentControlled =
          widget.value is String ? widget.value as String? : null;
      final current = currentControlled ?? _internalSingle;
      final next = current == itemValue ? null : itemValue;
      if (widget.value == null) {
        setState(() => _internalSingle = next);
      }
      widget.onValueChange?.call(next);
    }
  }

  @override
  Widget build(BuildContext context) {
    return _BTAccordionScope(
      isItemOpen: _isItemOpen,
      onToggle: _toggle,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: widget.children,
      ),
    );
  }
}

// ── BTAccordionItem ──────────────────────────────────────────────────────────

/// BTAccordionItem — single collapsible content panel (Figma 2473:2493).
///
/// Default visual: separator line at bottom, no background or border.
/// Place inside a [BTAccordion] for group open/close behaviour.
/// Use standalone for independent open/close control.
///
/// When [child] is null the header renders as a static non-interactive element
/// (no chevron, no tap gesture). The separator is still shown unless
/// [hasSeparator] is false.
///
/// Example:
/// ```dart
/// // Inside a group (preferred)
/// BTAccordion(
///   children: [
///     BTAccordionItem(
///       value: 'a',
///       title: 'First item',
///       subtext: Text('Optional subtext', style: TextStyle(color: Colors.blue)),
///       child: Text('Content A'),
///     ),
///   ],
/// )
///
/// // Standalone (uncontrolled)
/// BTAccordionItem(
///   title: 'FAQ question',
///   subtext: Text('Additional detail'),
///   child: Text('Answer text'),
/// )
/// ```
class BTAccordionItem extends StatefulWidget {
  const BTAccordionItem({
    required this.title,
    this.child,
    this.value,
    this.subtext,
    this.initiallyExpanded = false,
    this.disabled = false,
    this.hasSeparator = true,
    this.onChanged,
    super.key,
  });

  /// Unique identifier within a [BTAccordion] group. Required when used inside
  /// a group.
  final String? value;

  /// Header title text.
  final String title;

  /// Optional supporting widget shown below [title].
  final Widget? subtext;

  /// Content revealed when the item is open.
  /// When null, the header renders as a static non-interactive element
  /// (no chevron, no tap gesture).
  final Widget? child;

  /// Initial expanded state (standalone uncontrolled mode only).
  final bool initiallyExpanded;

  /// When true, the header is non-interactive (standalone mode only).
  final bool disabled;

  /// Show the 1px separator line below this item.
  /// @default true
  final bool hasSeparator;

  /// Called when the expanded state changes (standalone mode only).
  final ValueChanged<bool>? onChanged;

  @override
  State<BTAccordionItem> createState() => _BTAccordionItemState();
}

class _BTAccordionItemState extends State<BTAccordionItem>
    with SingleTickerProviderStateMixin {
  late bool _isOpen;
  late AnimationController _controller;
  late Animation<double> _heightFactor;
  late Animation<double> _chevronTurns;

  @override
  void initState() {
    super.initState();
    _isOpen = widget.initiallyExpanded;
    _controller = AnimationController(
      duration: const Duration(milliseconds: 250),
      vsync: this,
      value: _isOpen ? 1 : 0,
    );
    _heightFactor = CurvedAnimation(
      parent: _controller,
      curve: const Cubic(0.4, 0, 0.2, 1),
    );
    _chevronTurns = Tween<double>(begin: 0, end: 0.5).animate(
      CurvedAnimation(
        parent: _controller,
        curve: const Cubic(0.4, 0, 0.2, 1),
      ),
    );
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    final scope = _BTAccordionScope.maybeOf(context);
    if (scope != null && widget.value != null) {
      final shouldBeOpen = scope.isItemOpen(widget.value!);
      if (shouldBeOpen != _isOpen) {
        _isOpen = shouldBeOpen;
        if (_isOpen) {
          _controller.forward();
        } else {
          _controller.reverse();
        }
      }
    }
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  void _toggle() {
    if (widget.disabled) return;
    if (widget.child == null) return;

    final scope = _BTAccordionScope.maybeOf(context);
    if (scope != null && widget.value != null) {
      scope.onToggle(widget.value!);
      return;
    }

    setState(() => _isOpen = !_isOpen);
    if (_isOpen) {
      _controller.forward();
    } else {
      _controller.reverse();
    }
    widget.onChanged?.call(_isOpen);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    final header = _buildHeader(colors);
    final body = widget.child != null ? _buildBody() : const SizedBox.shrink();

    return Opacity(
      opacity: widget.disabled ? 0.5 : 1.0,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        mainAxisSize: MainAxisSize.min,
        children: [
          header,
          body,
          if (widget.hasSeparator)
            Container(height: 1, color: colors.border.primary),
        ],
      ),
    );
  }

  Widget _buildHeader(BTColorTheme colors) {
    if (widget.child == null) {
      return Padding(
        padding: EdgeInsets.symmetric(vertical: 8.0),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisSize: MainAxisSize.min,
                children: [
                  Text(
                    widget.title,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 14.0,
                      fontWeight: FontWeight.w500,
                      color: colors.text.primary,
                      height: 1.14,
                    ),
                  ),
                  if (widget.subtext != null) ...[
                    SizedBox(height: 4.0),
                    widget.subtext!,
                  ],
                ],
              ),
            ),
          ],
        ),
      );
    }

    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: widget.disabled ? null : _toggle,
      child: Padding(
        padding: EdgeInsets.symmetric(vertical: 8.0),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisSize: MainAxisSize.min,
                children: [
                  Text(
                    widget.title,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 14.0,
                      fontWeight: FontWeight.w500,
                      color: colors.text.primary,
                      height: 1.14,
                    ),
                  ),
                  if (widget.subtext != null) ...[
                    SizedBox(height: 4.0),
                    widget.subtext!,
                  ],
                ],
              ),
            ),
            SizedBox(width: 8.0),
            Padding(
              padding: EdgeInsets.only(top: 2.0),
              child: RotationTransition(
                turns: _chevronTurns,
                child: Icon(
                  Icons.expand_more,
                  size: 16,
                  color: colors.text.secondary,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildBody() {
    return SizeTransition(
      sizeFactor: _heightFactor,
      axisAlignment: -1,
      child: Padding(
        padding: EdgeInsets.only(bottom: 8.0),
        child: widget.child,
      ),
    );
  }
}

// ── BTAccordionCard ──────────────────────────────────────────────────────────

/// BTAccordionCard — self-contained expandable card with its own header
/// (Figma 2473:2493).
///
/// Renders a white card (background + 1px border + border-radius 8) with a
/// clickable header row (title + optional subtext + chevron). Tapping the
/// header expands or collapses the body.
///
/// When [child] is null the header renders as a static non-interactive element
/// (no chevron, no tap gesture) — useful for informational card headers.
///
/// The card body has no padding by default. Nest a [BTAccordion] for FAQ-style
/// collapsible item lists, or wrap arbitrary content in [Padding] if needed.
///
/// Example:
/// ```dart
/// // FAQ pattern — card header expands to reveal accordion items
/// BTAccordionCard(
///   title: 'Subscription & Billing',
///   subtext: Text('Common questions about billing'),
///   child: BTAccordion(
///     type: BTAccordionType.single,
///     children: [
///       BTAccordionItem(value: 'q1', title: 'How do I cancel?',
///           child: Text('...')),
///       BTAccordionItem(value: 'q2', title: 'Where is my invoice?',
///           child: Text('...')),
///     ],
///   ),
/// )
///
/// // Static header — no child, no chevron
/// const BTAccordionCard(title: 'Header - No Content')
///
/// // Custom content with padding
/// BTAccordionCard(
///   title: 'Settings',
///   child: Padding(
///     padding: const EdgeInsets.all(16),
///     child: Row(children: [BTButton(...), BTButton(...)]),
///   ),
/// )
/// ```
class BTAccordionCard extends StatefulWidget {
  const BTAccordionCard({
    required this.title,
    this.child,
    this.subtext,
    this.initiallyExpanded = false,
    this.expanded,
    this.onChanged,
    this.disabled = false,
    super.key,
  });

  /// Header title text.
  final String title;

  /// Optional supporting widget shown below [title].
  final Widget? subtext;

  /// Content revealed when the card is open.
  /// When null, the header renders as a static non-interactive element
  /// (no chevron, no tap gesture).
  final Widget? child;

  /// Initial expanded state (uncontrolled mode).
  final bool initiallyExpanded;

  /// Controlled expanded state. When set, [onChanged] must also be provided.
  final bool? expanded;

  /// Called when the expanded state changes (both controlled and uncontrolled).
  final ValueChanged<bool>? onChanged;

  /// When true, the card is non-interactive and visually dimmed.
  final bool disabled;

  @override
  State<BTAccordionCard> createState() => _BTAccordionCardState();
}

class _BTAccordionCardState extends State<BTAccordionCard>
    with SingleTickerProviderStateMixin {
  late bool _isOpen;
  late AnimationController _controller;
  late Animation<double> _heightFactor;
  late Animation<double> _chevronTurns;

  bool get _isControlled => widget.expanded != null;

  @override
  void initState() {
    super.initState();
    _isOpen = widget.expanded ?? widget.initiallyExpanded;
    _controller = AnimationController(
      duration: const Duration(milliseconds: 250),
      vsync: this,
      value: _isOpen ? 1 : 0,
    );
    _heightFactor = CurvedAnimation(
      parent: _controller,
      curve: const Cubic(0.4, 0, 0.2, 1),
    );
    _chevronTurns = Tween<double>(begin: 0, end: 0.5).animate(
      CurvedAnimation(
        parent: _controller,
        curve: const Cubic(0.4, 0, 0.2, 1),
      ),
    );
  }

  @override
  void didUpdateWidget(BTAccordionCard oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (_isControlled && widget.expanded != oldWidget.expanded) {
      final shouldBeOpen = widget.expanded!;
      if (shouldBeOpen != _isOpen) {
        _isOpen = shouldBeOpen;
        if (_isOpen) {
          _controller.forward();
        } else {
          _controller.reverse();
        }
      }
    }
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  void _toggle() {
    if (widget.disabled) return;
    if (widget.child == null) return;

    final next = !_isOpen;
    if (!_isControlled) {
      setState(() => _isOpen = next);
    }
    if (next) {
      _controller.forward();
    } else {
      _controller.reverse();
    }
    widget.onChanged?.call(next);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    return Opacity(
      opacity: widget.disabled ? 0.5 : 1.0,
      child: Container(
        width: double.infinity,
        decoration: BoxDecoration(
          color: colors.bg.primary,
          border: Border.all(color: colors.border.primary),
          borderRadius: BorderRadius.circular(8.0),
        ),
        clipBehavior: Clip.antiAlias,
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          mainAxisSize: MainAxisSize.min,
          children: [
            _buildHeader(colors),
            if (widget.child != null) _buildBody(),
          ],
        ),
      ),
    );
  }

  Widget _buildHeader(BTColorTheme colors) {
    // Static header when child is null
    if (widget.child == null) {
      return Padding(
        padding: EdgeInsets.symmetric(horizontal: 16.0, vertical: 12.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              widget.title,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 16.0,
                fontWeight: FontWeight.w700,
                color: colors.text.primary,
                height: 1.25,
              ),
            ),
            if (widget.subtext != null) ...[
              SizedBox(height: 4.0),
              widget.subtext!,
            ],
          ],
        ),
      );
    }

    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: widget.disabled ? null : _toggle,
      child: Padding(
        // Header padding stays constant — does NOT change on expand/collapse
        padding: EdgeInsets.symmetric(horizontal: 16.0, vertical: 12.0),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                mainAxisSize: MainAxisSize.min,
                children: [
                  Text(
                    widget.title,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 16.0,
                      fontWeight: FontWeight.w700,
                      color: colors.text.primary,
                      height: 1.25,
                    ),
                  ),
                  if (widget.subtext != null) ...[
                    SizedBox(height: 4.0),
                    widget.subtext!,
                  ],
                ],
              ),
            ),
            SizedBox(width: 8.0),
            Padding(
              padding: EdgeInsets.only(top: 2.0),
              child: RotationTransition(
                turns: _chevronTurns,
                child: Icon(
                  Icons.expand_more,
                  size: 16,
                  color: colors.text.secondary,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildBody() {
    return SizeTransition(
      sizeFactor: _heightFactor,
      axisAlignment: -1,
      // 16px horizontal aligns nested BTAccordionItem text with the card header.
      // 16px bottom gives breathing room before the card edge.
      child: Padding(
        padding: EdgeInsets.only(left: 16.0, right: 16.0, bottom: 16.0),
        child: widget.child ?? const SizedBox.shrink(),
      ),
    );
  }
}
